sql:
SELECT AVG(age) AS average_age, embarked
FROM passengers
WHERE embarked = 'S';

external_knowledge:
- The survival rate is inferred based on the number of survivors within each passenger class and embarkation port;
- The ranking is based on the number of survivors, with higher ranks indicating more survivors;
- Passenger classes include first, second, and third;
- Embarkation ports are Cherbourg (C), Queenstown (Q), and Southampton (S).;

sql:
SELECT AVG(fare) AS average_fare
FROM passengers
WHERE sex = 'female' AND embarked = '1';

SELECT name, sex
FROM passengers
WHERE passenger_id = 1;

SELECT COUNT(passenger_id) AS total_passengers, SUM(survived) AS survivors
FROM passengers
WHERE pclass = 1 AND embarked = '1';

SELECT survived, AVG(age) AS average_age
FROM passengers
GROUP BY survived;
